data:
:root {
  --bg0: #0b0f0c;
  --bg1: #121a14;
  --ink: #e8f0e4;
  --muted: #8a9a86;
  --accent: #c8f06c;
  --accent-dim: #7a9a3c;
  --warn: #ff7a59;
  --line: rgba(232, 240, 228, 0.12);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
  background:
    radial-gradient(1200px 600px at 80% -10%, rgba(200, 240, 108, 0.12), transparent 55%),
    radial-gradient(900px 500px at -10% 30%, rgba(40, 80, 50, 0.45), transparent 50%),
    linear-gradient(165deg, var(--bg0), #152018 55%, var(--bg0));
  color: var(--ink);
  font-family: var(--font-mono), ui-monospace, monospace;
}

body {
  min-height: 100dvh;
}

.shell {
  max-width: 440px;
  margin: 0 auto;
  padding: 1.25rem 1.1rem 3rem;
}

.hero {
  margin-bottom: 1.5rem;
}

.brand {
  margin: 0;
  font-family: var(--font-display), system-ui, sans-serif;
  font-weight: 700;
  letter-spacing: 0.18em;
  font-size: 0.75rem;
  color: var(--accent);
  text-transform: uppercase;
}

.hero h1 {
  margin: 0.45rem 0 0.55rem;
  font-family: var(--font-display), system-ui, sans-serif;
  font-size: clamp(1.7rem, 6vw, 2.15rem);
  line-height: 1.05;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.lede {
  margin: 0;
  color: var(--muted);
  font-size: 0.85rem;
  line-height: 1.45;
}

.hr-stage {
  position: relative;
  padding: 1.4rem 1rem 1rem;
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(18, 28, 20, 0.9), rgba(10, 14, 11, 0.95));
  overflow: hidden;
}

.pulse {
  display: flex;
  align-items: baseline;
  gap: 0.35rem;
}

.pulse.on .bpm {
  animation: beat 1s ease-in-out infinite;
}

.bpm {
  font-family: var(--font-display), system-ui, sans-serif;
  font-size: 5.2rem;
  line-height: 0.9;
  font-weight: 700;
  letter-spacing: -0.04em;
}

.unit {
  color: var(--accent);
  font-size: 1rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.spark {
  width: 100%;
  height: 72px;
  margin-top: 0.75rem;
  color: var(--accent);
  opacity: 0.9;
}

.meta {
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem 1rem;
  margin-top: 0.85rem;
  font-size: 0.72rem;
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.st.live {
  color: var(--accent);
}

.st.error {
  color: var(--warn);
}

.actions {
  display: grid;
  grid-template-columns: 1.3fr 1fr;
  gap: 0.65rem;
  margin: 1rem 0;
}

.btn {
  border: 1px solid var(--line);
  background: transparent;
  color: var(--ink);
  font: inherit;
  font-size: 0.82rem;
  padding: 0.9rem 0.75rem;
  cursor: pointer;
  transition: transform 0.15s ease, background 0.15s ease, border-color 0.15s ease;
}

.btn:active {
  transform: scale(0.98);
}

.btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.btn.primary {
  background: var(--accent);
  color: #10140e;
  border-color: var(--accent);
  font-family: var(--font-display), system-ui, sans-serif;
  font-weight: 700;
  letter-spacing: 0.02em;
}

.btn.secondary {
  margin-top: 0.65rem;
  width: 100%;
  border-color: var(--accent-dim);
  color: var(--accent);
}

.btn.ghost {
  background: rgba(255, 255, 255, 0.03);
}

.banner {
  margin: 0.75rem 0;
  padding: 0.85rem 0.9rem;
  border-left: 3px solid var(--accent);
  background: rgba(200, 240, 108, 0.06);
  color: var(--muted);
  font-size: 0.78rem;
  line-height: 1.4;
}

.banner a {
  color: var(--accent);
}

.err {
  color: var(--warn);
  font-size: 0.8rem;
}

.paste-block {
  margin-top: 1.4rem;
  padding-top: 1.1rem;
  border-top: 1px solid var(--line);
}

.paste-block h2,
.log h2 {
  margin: 0 0 0.4rem;
  font-family: var(--font-display), system-ui, sans-serif;
  font-size: 1.05rem;
}

.paste-block p {
  margin: 0 0 0.7rem;
  color: var(--muted);
  font-size: 0.78rem;
}

.paste-block code {
  color: var(--accent);
}

textarea {
  width: 100%;
  resize: vertical;
  background: #0a100c;
  border: 1px solid var(--line);
  color: var(--ink);
  font: inherit;
  font-size: 0.78rem;
  padding: 0.75rem;
}

.log {
  margin-top: 1.5rem;
}

.log ul {
  list-style: none;
  margin: 0.5rem 0 0;
  padding: 0;
  max-height: 280px;
  overflow: auto;
  border: 1px solid var(--line);
}

.log li {
  display: grid;
  grid-template-columns: 4.2rem 3.5rem 1fr;
  gap: 0.5rem;
  padding: 0.55rem 0.65rem;
  border-bottom: 1px solid var(--line);
  font-size: 0.72rem;
}

.log li.empty {
  display: block;
  color: var(--muted);
}

.log time {
  color: var(--muted);
}

.log strong {
  font-weight: 500;
  color: var(--accent);
}

.foot {
  margin-top: 2rem;
  color: var(--muted);
  font-size: 0.65rem;
  line-height: 1.4;
}

@keyframes beat {
  0%,
  100% {
    transform: scale(1);
  }
  35% {
    transform: scale(1.03);
  }
}

@media (min-width: 640px) {
  .shell {
    padding-top: 2.5rem;
  }
}
